@Component({
  selector: 'app-icon',
  standalone: true,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <svg
      [attr.width]="size()"
      [attr.height]="size()"
      viewBox="0 0 24 24"
      fill="none"
      aria-hidden="true"
      [innerHTML]="path()"
    ></svg>
  `,
  host: { class: 'app-icon', style: 'display: inline-flex; line-height: 0;' },
})
export class IconComponent {
  name = input.required<IconName>();
  size = input<number>(18);

  path(): string {
    return PATHS[this.name()];
  }
}
